Greedy insertion with fallback seed assignment using cost-aware vehicle selection and constraint validation per order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	seedIdx := dispatch.AssignsLen
	for idx := range oris {
		bestCostDelta := math.MaxFloat64
		bestVehicle := -1
		inserted := false
		for v := 0; v < MAXASSIGNS; v++ {
			if v >= dispatch.AssignsLen && v != seedIdx {
				continue
			}
			prevCost := dispatch.Assigns[v].Cost
			ok := dispatch.Assigns[v].AddShip(total_ship+idx, oris[idx], dess[idx])
			if ok {
				dispatch.Assigns[v].GenRoute()
				newCost := dispatch.Assigns[v].Cost
				if newCost >= 0 {
					costDelta := newCost - prevCost
					if bestVehicle == -1 || costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestVehicle = v
					}
				}
			}
			dispatch.Assigns[v].RemoveShip(total_ship + idx)
			if prevCost >= 0 {
				dispatch.Assigns[v].GenRoute()
			}
		}
		if bestVehicle >= 0 {
			dispatch.Assigns[bestVehicle].AddShip(total_ship+idx, oris[idx], dess[idx])
			dispatch.Assigns[bestVehicle].GenRoute()
			if bestVehicle >= dispatch.AssignsLen {
				dispatch.AssignsLen++
				seedIdx++
			}
			inserted = true
		}
		if !inserted {
			fallbackIdx := seedIdx
			if fallbackIdx >= MAXASSIGNS {
				for i := 0; i < dispatch.AssignsLen; i++ {
					if dispatch.Assigns[i].Cost < 0 {
						fallbackIdx = i
						break
					}
				}
			}
			if fallbackIdx < MAXASSIGNS {
				ok := dispatch.Assigns[fallbackIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						if fallbackIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen++
							seedIdx++
						}
						inserted = true
					} else {
						dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + idx)
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

